import React, { useState, useEffect } from 'react';
import { getSubscriptionTiers, getCurrentUsage, upgradeSubscription } from '../../services/subscription';
import { format } from 'date-fns';

const SubscriptionManagement = () => {
    const [tiers, setTiers] = useState([]);
    const [usage, setUsage] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [upgrading, setUpgrading] = useState(false);

    useEffect(() => {
        const loadData = async () => {
            try {
                const [tiersData, usageData] = await Promise.all([
                    getSubscriptionTiers(),
                    getCurrentUsage()
                ]);
                setTiers(tiersData);
                setUsage(usageData);
            } catch (err) {
                setError('Failed to load subscription data');
            } finally {
                setLoading(false);
            }
        };

        loadData();
    }, []);

    const handleUpgrade = async (tierId) => {
        setUpgrading(true);
        setError(null);

        try {
            await upgradeSubscription(tierId);
            // Reload usage data after upgrade
            const usageData = await getCurrentUsage();
            setUsage(usageData);
        } catch (err) {
            setError(err.response?.data?.error || 'Failed to upgrade subscription');
        } finally {
            setUpgrading(false);
        }
    };

    if (loading) return <div>Loading...</div>;

    return (
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="text-center">
                <h2 className="text-3xl font-extrabold text-gray-900 sm:text-4xl">
                    Subscription Plans
                </h2>
                <p className="mt-3 max-w-2xl mx-auto text-xl text-gray-500 sm:mt-4">
                    Choose the perfect plan for your API needs
                </p>
            </div>

            {error && (
                <div className="mt-4 bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded">
                    {error}
                </div>
            )}

            {usage && (
                <div className="mt-6 bg-white shadow rounded-lg p-6">
                    <h3 className="text-lg font-medium text-gray-900">Current Usage</h3>
                    <p className="mt-2 text-sm text-gray-500">
                        Period starting {format(new Date(usage.period_start), 'PPP')}
                    </p>
                    <p className="mt-2 text-2xl font-semibold text-gray-900">
                        {usage.current_usage.toLocaleString()} requests
                    </p>
                </div>
            )}

            <div className="mt-12 grid gap-8 lg:grid-cols-3">
                {tiers.map((tier) => (
                    <div key={tier.tier_id} className="bg-white shadow-lg rounded-lg">
                        <div className="p-8">
                            <h3 className="text-2xl font-semibold text-gray-900">
                                {tier.tier_name}
                            </h3>
                            <p className="mt-4 text-sm text-gray-500">{tier.description}</p>
                            <p className="mt-8">
                                <span className="text-4xl font-extrabold text-gray-900">
                                    ${tier.pricing}
                                </span>
                                <span className="text-base font-medium text-gray-500">/mo</span>
                            </p>
                            <ul className="mt-8 space-y-4">
                                <li className="flex items-center">
                                    <span className="text-green-500">✓</span>
                                    <span className="ml-3 text-gray-700">
                                        {tier.request_limit.toLocaleString()} requests per month
                                    </span>
                                </li>
                            </ul>
                            <button
                                onClick={() => handleUpgrade(tier.tier_id)}
                                disabled={upgrading}
                                className="mt-8 w-full bg-indigo-600 text-white py-2 px-4 rounded-md hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:opacity-50"
                            >
                                {upgrading ? 'Upgrading...' : 'Upgrade to ' + tier.tier_name}
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default SubscriptionManagement;
